  hexStr + base36Str
}

def toBase36(num: Long): String = {
  if (num == 0) "0"
  else {
    val digits = ListBuffer[String]()
    var n = num
    while (n > 0) {
      val remainder = n % 36
      val ch = if (remainder < 10) remainder.toString else ((remainder - 10 + 'A'.toInt).toChar).toString
      digits += ch
      n = n / 36
    }
    digits.reverse.mkString
  }
}
